import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do I measure my bra size?", a: "Measure your band size: wrap a soft measuring tape snugly under your bust. Round to the nearest even number. Measure your bust size: wrap the tape loosely at the fullest part. The difference between bust and band determines your cup size." },
  { q: "What cup size is the difference in inches?", a: "0-0.5 inches = AA, 0.5-1 inch = A, 1-2 inches = B, 2-3 inches = C, 3-4 inches = D, 4-5 inches = DD/E, 5-6 inches = DDD/F, 6-7 inches = G. Each additional inch adds one cup size." },
  { q: "What are sister sizes in bras?", a: "Sister sizes are bra sizes with the same cup volume but different band/cup letter combinations. For example, 34C, 36B, and 32D all have roughly the same cup volume. If a bra fits in the cup but not the band, try a sister size." },
  { q: "How often should I get re-measured for a bra?", a: "Bra size can change with weight changes, pregnancy, breastfeeding, or naturally over time. Experts recommend getting re-measured every 6-12 months or whenever your current bras feel uncomfortable." },
  { q: "What if the band measurement is an odd number?", a: "If your under-bust measurement is an odd number (e.g., 33 inches), round up to the nearest even number. Many calculators add 4-5 inches to odd measurements, but the modern approach is simply to round up for a snugger, more supportive fit." },
  { q: "How do I know if my bra fits correctly?", a: "Signs of a good fit: the band sits horizontally and parallel to the ground, the center panel lies flat against your chest, cups are smooth with no spillage or gaps, straps don't dig in or slide off. If any of these are off, try adjusting band size or cup size." },
  { q: "What is the most common bra size?", a: "Studies suggest the most commonly purchased bra size in the US is 34B, but the most commonly worn size that actually fits is estimated to be closer to 34DD or 36D - indicating that many women wear bras that are too large in the band and too small in the cup." },
];

const CUPS = ["AA","A","B","C","D","DD","DDD","G","H","I","J","K"];

export default function BraSizeCalculator() {
  const [band, setBand] = useState(34);
  const [bust, setBust] = useState(37);

  const diff = bust - band;
  const cupIdx = Math.max(0, Math.min(Math.round(diff) - 1, CUPS.length - 1));
  const cup = diff < 0.5 ? "AA" : CUPS[cupIdx] || "K+";
  const size = `${band % 2 === 0 ? band : band + 1}${cup}`;

  const sisters = [
    { band: (band % 2 === 0 ? band : band + 1) - 2, cup: CUPS[Math.min(cupIdx + 1, CUPS.length - 1)] },
    { band: (band % 2 === 0 ? band : band + 1) + 2, cup: CUPS[Math.max(cupIdx - 1, 0)] },
  ];

  return (
    <>
      <SEOHead
        title="Free Bra Size Calculator Online - Find Your Perfect Bra Size Instantly | CalcHive"
        description="Free online bra size calculator. Find your bra size from band and bust measurements with cup size and sister size guide instantly. 100% free for everyone, no signup required."
        canonical="/bra-size-calculator"
        keywords="free bra size calculator, bra size calculator online free, find my bra size free, cup size calculator free, sister size bra calculator free"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-lime-600 dark:text-lime-400 bg-lime-50 dark:bg-lime-950/50 px-3 py-1 rounded-full mb-4 inline-block">Everyday</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Bra Size Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free bra size calculator to find my bra size free from band and bust measurements. This bra size calculator online free also works as a cup size calculator free and sister size bra calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="band" label="Band Measurement (inches) - measure under the bust" value={band} min={28} max={50} step={1} onChange={setBand} format={v => `${v}"`} testId="input-band" />
            <SliderInput id="bust" label="Bust Measurement (inches) - measure at the fullest point" value={bust} min={28} max={60} step={0.5} onChange={setBust} format={v => `${v}"`} testId="input-bust" />
          </div>
          <motion.div key={`${band}-${bust}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-lime-500 to-lime-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Your Bra Size</p>
              <p className="text-7xl font-black text-white tracking-tight" data-testid="result-size">{size}</p>
              <p className="text-white/70 text-sm mt-1">Band: {band % 2 === 0 ? band : band + 1}" - Cup: {cup} - Diff: {(bust - band).toFixed(1)}"</p>
            </div>
            <div>
              <p className="text-sm font-semibold text-muted-foreground mb-2">Sister Sizes - same cup volume, different band</p>
              <div className="flex gap-3">
                {sisters.map(s => (
                  <div key={s.band} className="flex-1 bg-accent/60 border border-border rounded-xl p-4 text-center">
                    <p className="text-xs text-muted-foreground mb-1">Same cup volume</p>
                    <p className="text-2xl font-black text-foreground">{s.band}{s.cup}</p>
                  </div>
                ))}
              </div>
            </div>
          </motion.div>
        </section>
        <MedicalDisclaimer /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Bra Size for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Getting an accurate bra measurement requires two measurements: your band size and your bust size. Use a soft fabric tape measure and wear a non-padded bra or no bra at all for best results.</p>
          <ol className="space-y-3 text-muted-foreground list-decimal list-inside">
            <li><strong className="text-foreground">Measure your band:</strong> Wrap the tape measure snugly (but not tightly) around your ribcage, just under your bust. Keep the tape horizontal. Record in inches and round up to the nearest even number.</li>
            <li><strong className="text-foreground">Measure your bust:</strong> Wrap the tape loosely around the fullest part of your chest, keeping it level. Don't pull tight - this measurement should be relaxed.</li>
            <li><strong className="text-foreground">Calculate the difference:</strong> Subtract your band measurement from your bust measurement. This inch difference gives you your cup size.</li>
          </ol>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Cup Size = Bust Measurement (in) - Band Measurement (in)</p>
            <p className="text-xs text-muted-foreground mt-1">Example: 37" bust - 34" band = 3" difference = C cup - Size 34C</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Your Cup Size and Sister Size</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Difference (Bust - Band)", "Cup Size", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Less than 1\"", "AA", "Very flat, minimal projection"],
                  ["1\"", "A", "Small cup, minimal projection"],
                  ["2\"", "B", "Average cup size"],
                  ["3\"", "C", "Most common fitted size"],
                  ["4\"", "D", "Full cup"],
                  ["5\"", "DD / E", "Full cup, extended sizing begins"],
                  ["6\"", "DDD / F", "Plus cup"],
                  ["7\"", "G", "Extended plus sizing"],
                  ["8\"", "H", "Extended plus sizing"],
                  ["9\"", "I", "Specialty sizing"],
                  ["10\"", "J", "Specialty sizing"],
                ].map(([diff, cup, note]) => (
                  <tr key={diff} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{diff}</td>
                    <td className="py-2.5 px-4 text-lime-600 dark:text-lime-400 font-bold text-lg">{cup}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{note}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Bra Fitting Calculator for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Sister sizes are bra sizes that share the same cup volume but with different band/cup combinations. Going up one band size requires going down one cup letter to maintain the same volume (and vice versa).</p>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Smaller Band", "Your Size", "Larger Band"].map(h => <th key={h} className="text-center py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[["32D", "34C", "36B"], ["34D", "36C", "38B"], ["34DD", "36D", "38C"], ["36DD", "38D", "40C"], ["38D", "40C", "42B"]].map(([smaller, main, larger]) => (
                  <tr key={main} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 text-muted-foreground text-center">{smaller}</td>
                    <td className="py-2.5 px-4 font-bold text-foreground text-center text-lg">{main}</td>
                    <td className="py-2.5 px-4 text-muted-foreground text-center">{larger}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/bra-size-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


